(14, 'test 12/6/2023', 'sokhum', '2023-12-06', '[\"6570154d5a9bf.jpg\"]', 'e-journal', 'seavleylim@gmail.com', 'វិទ្យាសាស្ដ្រសត្វ', 'details', 'digital-book-php.pdf', 4158364, 0, 0, 0);

