(3, '1005', 'វិទ្យាសាស្រ្ដជលផល', '3', '<div id=\"contentsContainer\" style=\"box-sizing: inherit; color: rgb(95, 95, 95); font-family: Poppins, sans-serif; word-break: break-word;\"><div id=\"contents\" style=\"box-sizing: inherit; word-break: break-word;\"><p id=\"E694\" class=\"qowt-li-6_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word;\"><span style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\"><span id=\"E695\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ចំណេះដឹងមូលដ្ឋានដែលបេក្ខជនត្រូ</span><span id=\"E696\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">វចេះសម្រាប់ទៅសិក្សាមុខជំនាញនេះ​&nbsp;</span><span id=\"E697\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">៖</span></span><span id=\"E698\" class=\"qowt-font9-KhmerOSSiemreap\" style=\"box-sizing: inherit; word-break: break-word;\"></span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial;\"><li class=\"qowt-li-6_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E698\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">គីមីវិទ្យា​</span>,</li><li class=\"qowt-li-6_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E698\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជីវវិទ្យា</span>,</li></ul><p id=\"E700\" class=\"qowt-li-6_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">ការសិក្សាដើម្បីទទួលបានសញ្ញាបត្របរិញ្ញាបត្ររងលើមុខជំនាញនេះ ៖</span><span id=\"E702\" class=\"qowt-font9-KhmerOSSiemreap\" style=\"box-sizing: inherit; word-break: break-word;\"></span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial;\"><li class=\"qowt-li-6_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E702\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">មានរយៈពេល ២ ឆ្នាំ យ៉ាងតិច​&nbsp;</span><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៦០ ក្រេឌីត</span>,</li></ul></div></div><div id=\"contentsContainer\" style=\"box-sizing: inherit; color: rgb(95, 95, 95); font-family: Poppins, sans-serif; word-break: break-word;\"><div id=\"contents\" style=\"box-sizing: inherit; word-break: break-word;\"><p id=\"E703\" class=\"qowt-li-6_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">ចំណេះដឹង និងបំណិនដែលនិស្សិតទទួលបានក្រោយពីបញ្ចប់ការសិក្សារយៈពេល២ឆ្នាំ៖</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial;\"><li id=\"E705\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E706\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីវិធីសាស្រ្តចិញ្ចឹមសត្វទឹក</span>,</li><li id=\"E707\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E708\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីការជ្រើសរើស និងបង្កាត់ពូជសត្វទឹក</span>,</li><li id=\"E709\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E710\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីការគ្រប់គ្រងកាកសំណល់ និងបរិស្ថានក្នុងទឹក</span>,</li><li id=\"E711\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E712\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីវិធីសាស្រ្តព្យាបាលសត្វទឹក</span>,</li><li id=\"E713\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E714\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីការត្រួតពិនិត្យគុណភាពវត្ថុធាតុដើមរបស់ចំណីសត្វទឹក</span>,</li><li id=\"E715\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E716\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីការលាយចំណីសត្វទឹកតាមវិធីសាស្រ្ត</span>,</li><li id=\"E717\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E718\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីការប្រើបា្រស់ និងជួសជុលថែទាំឧបករណ៍ និងកសិដ្ឋានសត្វទឹក</span>,</li><li id=\"E719\" class=\"qowt-li-0_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E720\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីការគ្រប់គ្រងផ្នែកផលិត និងទីផ្សារ</span>,</li></ul><p id=\"E724\" class=\"qowt-li-3_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">អង្គភាព ឬមូលដ្ឋានដែលអ្នកសិក្សាចប់មុខជំនាញនេះអាចទៅបម្រើការងារ៖</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial;\"><li id=\"E727\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E728\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជាអ្នកបច្ចេកទេសផ្នែកផលិតនៅកសិដ្ឋាន</span>,</li><li id=\"E729\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E730\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជា</span><span id=\"E731\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">បុគ្កលិក</span><span id=\"E732\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">គ្រប់គ្រងគុណភាពនៅរោងចក្រផលិតចំណីសត្វ</span><span id=\"E733\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ទឹក</span><span id=\"E734\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ឬចំណីអាហារ</span>,</li><li id=\"E735\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E736\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជាបុគ្គលិកផ្នែកលក់ចំណីនិងថ្នាំសត្វ</span><span id=\"E737\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ទឹក</span>,</li><li id=\"E738\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E739\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជាម្ចាស់អាជីវកម្មលក់ចំណីសត្វទឹក ឬបើកកសិដ្ឋានចិញ្ចឹមសត្វទឹក</span>, ,</li></ul></div></div>                                        ', '[\"6580ebc806327.jpg\"]', 1, '2023-12-19 08:03:04'),
(4, '1006', 'កុំព្យូទ័រធុរកិច្ច', '4', '<p id=\"E743\" class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\"><span id=\"E744\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ចំណេះដឹងមូលដ្ឋានដែលបេក្ខជនត្រូវចេះសម្រាប់ទៅសិក្សាមុខជំនាញនេះ ៖</span><span id=\"E745\" class=\"qowt-font9-KhmerOSSiemreap\" style=\"box-sizing: inherit; word-break: break-word;\"></span></span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E746\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">គណិតវិទ្យា</span>,</li><li class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E749\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">មូលដ្ឋានអេឡិចត្រូនិច</span><span id=\"E750\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">&nbsp;</span><span id=\"E751\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ឬមូលដ្ឋានការប្រើប្រាស់កុំព្យូទ័រ</span>,</li><li class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E751\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">មានចំណង់ចំណូលចិត្តខាងផ្នែកកុំព្យូទ័រ​</span>,</li></ul><p id=\"E754\" class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\"><span id=\"E755\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ការសិក្សាដើម្បីទទួលបានសញ្ញាបត្របរិញ្ញាបត្ររងលើមុខជំនាញនេះ ៖</span><span id=\"E756\" class=\"qowt-font9-KhmerOSSiemreap\" style=\"box-sizing: inherit; word-break: break-word;\"></span></span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E757\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">មានរយៈពេល ២ ឆ្នាំ មិនតិចជាង ៦០ ក្រេឌីត</span>,</li></ul><p id=\"E759\" class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">ចំណេះដឹង និងបំណិនដែលនិស្សិតទទួលបានក្រោយពីបញ្ចប់ការសិក្សាអស់រយៈពេល២ឆ្នាំ​ ៖</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li id=\"E761\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E762\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">យល់ដឹងពីមូលដ្ឋានការប្រើប្រាស់កុំព្យូទ័រនិងបច្ចេកវិទ្យាអ៊ីនធឺណែត</span>,</li><li id=\"E763\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E764\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អាចប្រើប្រាស់ប្រព័ន្ធប្រតិបត្តការ</span><span id=\"E765\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">&nbsp;Windows&nbsp;</span><span id=\"E766\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">បាន</span>,</li><li id=\"E767\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E768\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អាចរៀបចំនិងគ្រប់គ្រងប្រព័ន្ធទិន្នន័យបាន</span>,</li><li id=\"E769\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E770\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អាចតម្លើងប្រព័ន្ធកុំព្យូទ័របាន</span>,</li><li id=\"E771\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E772\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អាចយល់ដឹងនិងការបង្កើតវ៉េបសាយបាន</span>,</li><li id=\"E773\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E774\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អាចតម្លើងប្រព័ន្ធបណ្តាញកុំព្យូទ័រ</span><span id=\"E775\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">បាន</span>,</li><li id=\"E776\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E777\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អាចរចនារូបភាពក្រាហ្វិចបាន</span>,</li><li id=\"E778\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E779\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អាចបម្រើសេវាកម្មផ្សេងៗក្នុងការតម្លើងបណ្តាញណែតវឺកនិងប្រព័ន្ធកុំព្យូទ័របាន</span>,</li></ul><p id=\"E780\" class=\"qowt-li-11_0 qowt-list qowt-stl-ListParagraph\" style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\"><span id=\"E781\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">អង្គភាព ឬមូលដ្ឋានដែលអ្នកសិក្សាចប់មុខជំនាញនេះអាចទៅបម្រើ</span><span id=\"E782\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ការងារ៖</span></span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li id=\"E783\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E784\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជាគ្រូបង្រៀនកុំព្យូទ័រនៅតាមគ្រឹះស្ថានសិក្សា</span>,</li><li id=\"E785\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E786\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជាអ្នកបច្ចេកទេសកុំព្យូទ័រនៅតាមបណ្តាសហគ្រាស និងក្រុមហ៊ុន</span>,</li><li id=\"E787\" class=\"qowt-li-5_0 qowt-list\" data-contextual-spacing=\"true\" style=\"box-sizing: inherit; word-break: break-word;\"><span id=\"E788\" class=\"qowt-font9-KhmerOSSiemreap\" khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\">ជាអ្នករចនាក្រាហ្វិកនិងបង្កើតគេហទំព័រសម្រាប់ធុរកិច្ចនៅតាមបណ្តាសហគ្រាស និងក្រុមហ៊ុន</span>,</li></ul>                                        ', '[\"6580ebfada4ed.jpg\",\"6580ebfadaa37.jpg\"]', 1, '2023-12-19 08:03:54'),
(5, '1007', 'បច្ចេកវិទ្យាកុំព្យូទ័រ', '5', '<h2 style=\"box-sizing: inherit; margin-bottom: 20px; word-break: break-word; clear: both; color: rgb(58, 58, 58); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";=\"\" font-size:=\"\" 18px;\"=\"\"><span style=\"font-weight: bolder;\">លក្ខខណ្ឌនៃការចូលរៀន</span></span></h2><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">– មានសញ្ញាបត្របច្ចេកទេស និងវិជ្ជាជីវៈ៣ (កម្រិត៤) ឬ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">– ប្រឡងធ្លាក់មធ្យមសិក្សាទុតិយភូមិ ឬ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">– មានវិញ្ញាបនបត្រថ្នាក់ឆ្នាំសិក្សាមូលដ្ឋាន​ ឬ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">– មានសញ្ញាបត្រដែលមានតម្លៃស្មើ</span></p><h2 style=\"box-sizing: inherit; margin-bottom: 20px; word-break: break-word; clear: both; color: rgb(58, 58, 58); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";=\"\" font-size:=\"\" 18px;\"=\"\"><span style=\"font-weight: bolder;\">សមត្ថភាពផ្នែកវិជ្ជាជីវៈដែលរំពឹងទុក</span></span></h2><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">១. ប្រើប្រាស់ភាសាសម្រាប់ទំនាក់ទំនងការងារ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">២. ប្រើប្រាស់ប្រព័ន្ធប្រតិបត្តិកុំព្យូទ័រ និងកម្មវិធីសម្រាប់ការងាររដ្ឋបាល</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៣. រចនាក្រាហ្វិក និងកាត់តវិឌីអូដោយប្រើប្រាស់កម្មវិធីកុំព្យូទ័រ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៤. ដំឡើងកុំព្យូទ័រ កម្មវិធីកុំព្យូទ័រ និងការថែទាំ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៥. ដំឡើងប្រព័ន្ធបណ្តាញអ៊ីនធើណេត និងការថែទាំបណ្តាញ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៦. អភិវឌ្ឍគេហទំព័រ និងគ្រប់គ្រងប្រព័ន្ធទិន្នន័យ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៧. សរសេរកូដសម្រាប់បញ្ជាលើឧបករណ៍ IoTs</span></p><h2 style=\"box-sizing: inherit; margin-bottom: 20px; word-break: break-word; clear: both; color: rgb(58, 58, 58); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";=\"\" font-size:=\"\" 18px;\"=\"\"><span style=\"font-weight: bolder;\">ឱកាសការងារ</span></span></h2><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">១. បុគ្គលិកបង្រៀនទាក់ទងនឹងកុំព្យូទ័រទាំងផ្នែករដ្ឋ និងឯកជន</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">២. ជាអ្នកបច្ចេកទេស IT ក្នុងអង្គភាពរដ្ឋ និងឯកជន</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៣. ជាអ្នកដំឡើង ថែទាំប្រព័ន្ធបណ្តាញកុំព្យូទ័រ និងអ៊ីនធើណេត</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៤. ជាអ្នកអភិវឌ្ឍកម្មវិធីកុំព្យូទ័រ និងបង្កើតគេហទំព័រ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៥. ជាអ្នកអភិវឌ្ឍន៍ប្រព័ន្ធឆ្លាតវ័យបញ្ជាដោយស្វ័យប្រវត្តិ</span></p><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">៦. ប្រកបអាជីពផ្ទាល់ខ្លួន បន្តការសិក្សាទាំងក្នុង និងក្រៅប្រទេស</span></p>                                        ', '[\"6580ec3436b34.jpg\",\"6580ec3436e85.jpg\"]', 1, '2023-12-19 08:04:52'),
(6, '1008', 'ការដំឡើងប្រព័ន្ធអគ្គិសនី', '6', '<p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word;\"><span style=\"font-weight: bolder;\">ចំណេះដឹងមូលដ្ឋានដែលបេក្ខេជនត្រូវចេះសម្រាប់ទៅសិក្សាមុខជំនាញនេះ ៖</span></span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">រូបវិទ្យា</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">ភាសាអង់គ្លេស</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">គណិតវិទ្យា</span>,</li></ul><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">ការសិក្សាដើម្បីទទួលបានសញ្ញាបត្របរិញ្ញាបត្ររងលើមុខជំនាញនេះ</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">មានរយៈពេល ២ ឆ្នាំ យ៉ាងតិច ៦០ ក្រេឌីត</span>,</li></ul><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">ចំណេះដឹង និងបំណិនដែលនិស្សិតទទួលបានក្រោយ</span><span khmer=\"\" os=\"\" siemreap\";\"=\"\">ពីបញ្ចប់ការសិក្សារយៈពេល ២ ឆ្នាំ៖</span></span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អាចជួសជុលឧបករណ៍ប្រើប្រាស់អគ្គិសនីបាន</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អាចដំឡើងឧបករណ៍ និងប្រព័ន្ធបណ្តាញអគ្គិសនីបាន</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អាចវិភាគ និងដោះស្រាយបញ្ហាប្រព័ន្ធអគ្គិសនីបាន</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អាចគូសប្លង់ប្រព័ន្ធអគ្គីសនីក្នុងអាគារនិងរោងចក្របាន</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អាចបំពាក់សម្ភារបរិក្ខារត្រជាក់ និងម៉ាស៊ីនត្រជាក់បាន</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អាចជួសជុល និងការបញ្ជាម៉ូទ័រអគ្គិសនីបាន</span>,</li></ul><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">អង្គភាព ឬមូលដ្ឋានដែលអ្នកសិក្សាចប់មុខជំនាញនេះអាចទៅបម្រើការងារ៖</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អ្នកគូសប្លង់ប្រព័ន្ធអគ្គីសនី</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">បុគ្គលិកទទួលខុសត្រូវផ្នែកជួសជុល​ និងថែទាំប្រព័ន្ធអគ្គិសនី</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">បុគ្គលិកគ្រប់គ្រងប្រព័ន្ធអគ្គិសនី​ និងបញ្ជាម៉ូទ័រ</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">បង្កើតអាជីវផ្ទាល់ខ្នួន</span>,</li></ul>                                        ', '[\"6580ec6714af6.jpg\",\"6580ec6714dcf.jpg\",\"6580ec6715078.jpg\",\"6580ec671535e.jpg\"]', 1, '2023-12-19 08:05:43');
INSERT INTO `major_tb` (`id`, `major_code`, `major_title`, `select_department`, `major_detials`, `image`, `status`, `creationdate`) VALUES
(7, '1009', 'បច្ចេកវិទ្យាអាហារ', '7', '<p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">ចំណេះដឹងមូលដ្ឋានដែលបេក្ខជនត្រូវចេះសម្រាប់ទៅសិក្សាមុខជំនាញនេះ ៖</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">ជីវវិទ្យា</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">គីមីវិទ្យា</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">គណិតវិទ្យា</span>,</li></ul><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">ការសិក្សាដើម្បីទទួលបានសញ្ញាបត្របរិញ្ញាបត្ររងលើមុខជំនាញនេះ</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">មានរយៈពេល ២ ឆ្នាំ យ៉ាងតិច ៦០ ក្រេឌីត</span>,</li></ul><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">ចំណេះដឹង និងបំណិនដែលនិស្សិតទទួលបានក្រោយពីបញ្ចប់ការសិក្សារយៈពេល ២ ឆ្នាំ៖</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">កែច្នៃអាហារដោយកម្មវីធីផ្សេងៗ</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">កែច្នៃអាហារតាមប្រភេទរបស់ផលិតផល</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">វិភាគគុណភាពផលិតផលអាហារ</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">គ្រប់គ្រងគុណភាពផលិតផលអាហារ</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">ផលិតអាហារស្របតាមមាត្រដ្ឋានគុណភាព</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អនុវត្តន៍តាមគោលការណ៍វិធីសាស្រ្តដែលល្អក្នុងការផលិត​(GMP)</span>,</li></ul><p style=\"box-sizing: inherit; margin-bottom: 1.5em; word-break: break-word; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\" style=\"box-sizing: inherit; word-break: break-word; font-weight: bolder;\">អង្គភាព ឬមូលដ្ឋានដែលអ្នកសិក្សាចប់មុខជំនាញនេះអាចទៅបម្រើការងារ៖</span></p><ul style=\"box-sizing: inherit; margin-right: 0px; margin-bottom: 1.5em; margin-left: 0px; word-break: break-word; list-style-position: initial; list-style-image: initial; color: rgb(95, 95, 95); font-family: Poppins, sans-serif;\"><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">អ្នកវិភាគគុណភាពក្នុងរោងចក្រផលិតអាហារកែច្នៃ</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">បុគ្គលិកទទួលខុសត្រូវផ្នែកផលិតអាហារ</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">បុគ្គលិកគ្រប់គ្រងគុណភាពអាហារ</span>,</li><li style=\"box-sizing: inherit; word-break: break-word;\"><span khmer=\"\" os=\"\" siemreap\";\"=\"\">បង្កើតអាជីវកម្មផ្ទាល់ខ្នួន</span>, ,</li></ul>                                        ', '[\"6580ec9b5c729.jpg\",\"6580ec9b5ca57.jpg\",\"6580ec9b5cd65.jpg\",\"6580ec9b5cfcc.jpg\",\"6580ec9b5d25b.jpg\",\"6580ec9b5d4f2.jpg\"]', 1, '2023-12-19 08:06:35');

