--
-- Table structure for table `teacher_tb`
--

CREATE TABLE `teacher_tb` (
  `id` int(11) NOT NULL,
  `teacher_id` varchar(100) NOT NULL,
  `firstname` varchar(100) NOT NULL,
  `lastname` varchar(100) NOT NULL,
  `teacher_mail` varchar(100) NOT NULL,
  `phone` varchar(100) NOT NULL,
  `select_major` int(11) NOT NULL,
  `specialty` varchar(100) NOT NULL,
  `select_role` varchar(100) NOT NULL,
  `teacher_password` varchar(100) NOT NULL,
  `image` varchar(255) NOT NULL,
  `teacher_detials` text NOT NULL,
  `teacher_code` varchar(100) NOT NULL,
  `teacher_status` varchar(100) NOT NULL
